import "../Footer/Footer.scss";
import "bootstrap/dist/css/bootstrap.min.css";
import { Button } from "react-bootstrap";
import {ImGithub} from "react-icons/im";
import { AiOutlineBehance, AiFillLinkedin } from "react-icons/ai";

const Footer = () => {
  return (
    <div className="footer">
      <div className="footer__container">
        <div className="footer__header">
          <h3>Get In Touch</h3>
        </div>
        <div className="footer__desc">
          <p className="text-skyblue">
            Although I’m not currently looking for any new opportunities, my
            inbox is always open. Whether you have a question or just want to
            say hi, I’ll try my best to get back to you!
          </p>
        </div>
        <div className="footer__cta">
          <Button className="app__hero__cta btn-green my-3">Say Hello</Button>
        </div>
        <div className="footer__icon">
          <div className="footer__icon__github">
            <ImGithub />
          </div>
          <div className="footer__icon__behance">
            <AiOutlineBehance />
          </div>
          <div className="footer__icon__linkedin">
            <AiFillLinkedin />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Footer;
